const year = items[0]?.json["Date Formated"]?.split(" ")[1] || new Date().getFullYear();

// initialize 12 months with 0
const totals = Object.fromEntries(
  Array.from({ length: 12 }, (_, i) => [
    `${String(i + 1).padStart(2, "0")} ${year}`, 0
  ])
);

// sum amounts if input is not empty
for (const { json } of items || []) {
  const key = json["Date Formated"];
  if (key && totals.hasOwnProperty(key)) {
    totals[key] += Number(json["Amount in basic currency"]) || 0;
  }
}

// return 1 item with all months
return [{ json: Object.fromEntries(
  Object.entries(totals).map(([month, total]) => [month, +total.toFixed(2)])
) }];

