const [credit, debit] = items.map(i => i.json);

const result = Object.fromEntries(
  Object.keys(credit).map(month => [month, +(credit[month] - (debit[month] || 0)).toFixed(2)])
);

return [{ json: result }];

const actuals = items[1].json;
const budget = items[0].json;

// dynamic key from Metric
const key = items[0].json.Metric || "messages";

// generate messages if actual > budget
let result = Object.keys(budget)
  .filter(month => actuals[month] > budget[month])
  .map(month => `Budget exceeded in ${month} - budget: ${budget[month]}, actual: ${actuals[month]}`);

// fallback if empty
if (result.length === 0) {
  result = ["All costs within the budget"];
}

// return single item with dynamic key
return [{ json: { [key]: result } }];

const input = items.map(i => i.json);

let body = "Budget Report:\n\n";

for (const section of input) {
  for (const [metric, messages] of Object.entries(section)) {
    body += `${metric}:\n`;
    for (const msg of messages) {
      body += `- ${msg}\n`;
    }
    body += "\n"; // add extra line between sections
  }
}

// return single item with email body
return [{ json: { email_body: body.trim() } }];
